mapper.update:
UPDATE nhan_vien SET
ho_ten = #{hoTen},
ngay_sinh = #{ngaySinh},
gioi_tinh = #{gioiTinh}
WHERE ma_nhan_vien = #{maNhanVien}

UPDATE nhan_vien SET
    hoat_dong = true
WHERE ma_nhan_vien = #{maNhanVien}

mapper.delete:
UPDATE nhan_vien SET
    hoat_dong = false
WHERE ma_nhan_vien = #{maNhanVien}

mapper.select:
SELECT IFNULL(MAX(CAST(RIGHT(ma_nhan_vien, 4) AS UNSIGNED)), 0)
FROM chuc_vu
WHERE ma_phong_ban = #{maPhongBan}
